import axios from 'axios';
import React, { useEffect, useState } from 'react'
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { useGetAllProductsQuery } from './MyorderApi';

const MyOrder = () => {
  const [orderData, setorderData] = useState();
  var userid= sessionStorage.getItem("UserInfoID")

  const [movieData, setMovieData] = useState([]);

    const getMovieList  = async () => {

        const url = `http://localhost:1313/myorder/${userid}`

        const response = await fetch (url);
                try {
                    const responseJson = await response.json();
                    console.log(responseJson);
                    setMovieData = (responseJson.results);
                } catch (err) {
                    console.error(err);
                }

    };

     useEffect(() => {
    const fetchData = async () => {
      await fetch("http://localhost:2020/api/table")
        .then(async (res) => {
          const data = await res.json();
          setRenderData(data?.data);
        })
        .catch((err) => {
          console.log("err", err);
        });
    };
    fetchData();
  }, []);
    useEffect (()=> {
     getMovieList();
    }, []);

  return (
    <div>
      my order {orderData}
    </div>
  )
}

export default MyOrder
